SELECT COUNT(*) FROM inventory t1, product t2,store t3
WHERE t1.product_id = t2.product_id

	AND t1.store_id = #{inv.storeId}


	AND t2.product_name like concat('%',#{inv.productName},'%')


	AND t1.inventory_state = #{inv.inventoryState}

SELECT t1.*,t2.product_name,t3.store_name,inventoryCode.user_code AS userCode,createCode.user_code AS createUserCode FROM inventory t1 JOIN product t2 ON t1.product_id = t2.product_id JOIN store t3 ON t1.store_id = t3.store_id LEFT JOIN user_info inventoryCode ON t1.inventory_by = inventoryCode.user_id LEFT JOIN user_info createCode ON t1.create_by = createCode.user_id
AND t1.store_id = #{inv.storeId}
AND t2.product_name like concat('%',#{inv.productName},'%')
AND t1.inventory_state = #{inv.inventoryState}
order by t1.create_time desc LIMIT #{page.limitIndex},#{page.pageSize}
